import * as raw from './raw';
export const get = (http, params) => {
  return raw.get(http, `/organizations/${params.organizationId}/semantic/search-index/${params.indexId}`);
};
export const getMany = (http, params) => {
  return raw.get(http, `/organizations/${params.organizationId}/semantic/search-index`, {
    params: params.status ? {
      status: params.status
    } : undefined
  });
};
export const getManyForEnvironment = (http, params) => {
  return raw.get(http, `/spaces/${params.spaceId}/environments/${params.environmentId}/semantic/search-index`, {
    params: params.status ? {
      status: params.status
    } : undefined
  });
};
export const create = (http, params, data) => {
  return raw.post(http, `/organizations/${params.organizationId}/semantic/search-index`, data);
};
export const del = (http, params) => {
  return raw.del(http, `/organizations/${params.organizationId}/semantic/search-index/${params.indexId}`);
};